proof:
by
      -- By definition of $Ber(u, p)$, we know that the measure on the set of functions from $\iota$ to $\{0, 1\}$ induced by $Ber(u, p)$ is the product of $p$-bernoulli distributions on $u$.
      have h_prod : (Measure.map (fun ω => fun i => i ∈ X ω) P) = infinitePi fun i => toNNReal p • dirac (i ∈ u) + toNNReal (σ p) • dirac False := by
        convert hX.map_eq using 1;
        rw [ bernoulliOn_eq_map ];
        exact?;
      rw [ iIndepFun_iff_measure_inter_preimage_eq_mul ];
      intro S sets hsets
      have h_prod_measure : (Measure.map (fun ω => fun i => i ∈ X ω) P) (⋂ i ∈ S, {f : ι → Prop | f i ∈ sets i}) = ∏ i ∈ S, (Measure.map (fun ω => fun i => i ∈ X ω) P) {f : ι → Prop | f i ∈ sets i} := by
        rw [ h_prod ];
        convert MeasureTheory.Measure.infinitePi_pi _ _;
        any_goals tauto;
        · exact?;
        · rename_i i hi;
          convert MeasureTheory.Measure.infinitePi_pi _ _;
          rotate_left;
          rotate_left;
          exact?;
          exact { i };
          use fun _ => sets i;
          · aesop;
          · aesop;
          · simp +decide [ MeasureTheory.Measure.add_apply, MeasureTheory.Measure.smul_apply ];
        · intro i; constructor; aesop;
      rw [ Measure.map_apply_of_aemeasurable ] at h_prod_measure;
      · convert h_prod_measure using 1;
        · exact congr_arg _ ( by ext; simp +decide [ Set.mem_iInter ] );
        · rw [ Finset.prod_congr rfl ] ; intros ; rw [ Measure.map_apply_of_aemeasurable ] ; aesop;
          · fun_prop;
          · exact measurable_pi_apply _ ( hsets _ ‹_› );
      · exact?;
      · exact MeasurableSet.biInter ( Finset.countable_toSet S ) fun i hi => measurable_pi_apply i ( hsets i hi )

